class AuthService:
    def __init__(self, db: DatabaseClient):
        self.db = db

    def get_user_by_token(self, token: str):
        result = self.db.fetch_one(
            "SELECT * FROM users WHERE token = %s", (token,)
        )
        if result is None:
            return None
        return {
            'id': result['id'],
            'email': result['email'],
            'role': result['role'],
        }

